public boolean xyBalance(String str) {
    int yCount = 0;
    for (char c : str.toCharArray()) {
        if (c == 'x') {
            yCount = 0;
        } else if (c == 'y') {
            yCount++;
        }
        if (yCount == 0 && c == 'x') {
            return false;
        }
    }
    return true;
}

