Code:
public boolean canBalance(int[] nums) {
    int totalSum = 0;
    for(int i=0;i<nums.length;i++){
        totalSum += nums[i];
    }

    int leftSum = 0;
    for(int j=0; j<nums.length; j++){
        totalSum -= nums[j];
        if(totalSum == leftSum){
            return true;
        }
        leftSum += nums[j];
    }

    return false;
}
